mapper.select:



		AND menu_name like concat('%', #{menuName}, '%')


		AND visible = #{visible}


		AND status = #{status}



		AND tenant_id = COALESCE(#{tenantId}, 1)


order by parent_id, order_num

select distinct m.menu_id, m.parent_id, m.menu_name, m.path, m.component, m.query, m.route_name, m.visible, m.status, COALESCE(m.perms,'') as perms, m.is_frame, m.is_cache, m.menu_type, m.icon, m.order_num, m.create_time from sys_menu m left join sys_role_menu rm on m.menu_id = rm.menu_id left join sys_user_role ur on rm.role_id = ur.role_id left join sys_role ro on ur.role_id = ro.role_id left join sys_user u on ur.user_id = u.user_id where ur.user_id = #{params.userId}
AND m.menu_name like concat('%', #{menuName}, '%')
AND m.visible = #{visible}
AND m.status = #{status}
AND m.tenant_id = COALESCE(#{tenantId}, 1)
order by m.parent_id, m.order_num


where menu_name= #{menuName} and parent_id = #{parentId}

	AND tenant_id = COALESCE(#{tenantId}, 1)

limit 1
